\par \pard\fi0\li0\tx705\tx1410\tx2130\tx2835\tx3540\tx4245\tx4950\tx5670\tx6375\tx7080\tx7785\tx8490\tx8640\qj\ri0\sb60\sa60\itap0 \plain \f1\lang1033\fs20 Vgl. \plain \f1\scaps\lang1033\fs20 Grieshaber I, 55\plain \f1\scaps\lang1033\fs20 -62\plain \f1\lang1033\fs20 .}

